const t=document.getElementById("menu-toggle"),d=document.getElementById("mobile-menu");t?.addEventListener("click",()=>{const e=t.getAttribute("aria-expanded")==="true";t.setAttribute("aria-expanded",String(!e)),d?.toggleAttribute("hidden")});d?.addEventListener("click",e=>{e.target.matches("a")&&(t?.setAttribute("aria-expanded","false"),d.setAttribute("hidden",""))});const n=document.querySelector(".nav-dropdown-btn"),i=document.querySelector(".dropdown-menu");n?.addEventListener("click",e=>{e.stopPropagation();const a=n.getAttribute("aria-expanded")==="true";n.setAttribute("aria-expanded",String(!a))});document.addEventListener("click",e=>{i?.contains(e.target)||n?.setAttribute("aria-expanded","false")});i?.addEventListener("click",e=>e.stopPropagation());
